import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../lib/supabase';
import Navbar from '../components/Navbar';
import styles from './Dashboard.module.css';
import { MapContainer, TileLayer, Marker, Popup, useMap } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';

// Fix Leaflet default marker icons
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon-2x.png',
  iconUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon.png',
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-shadow.png',
});

const CLAUDE_API = 'https://claude-proxy.davidlimyk.workers.dev';
const MODEL = 'claude-sonnet-4-20250514';

const STANDARD_CATEGORIES = [
  { id: 'food', label: '🍽️ Food & Dining', desc: 'Restaurants, cafes, street food' },
  { id: 'shopping_malls', label: '🏬 Shopping Malls', desc: 'Major malls and retail centres' },
  { id: 'specialty_shops', label: '🛍️ Specialty Shops', desc: 'Local markets, boutiques, artisan shops' },
  { id: 'attractions', label: '🏛️ Places of Interest', desc: 'Landmarks, museums, heritage sites' },
  { id: 'nature', label: '🌿 Nature & Parks', desc: 'Parks, gardens, scenic spots' },
  { id: 'culture', label: '🎭 Culture & Arts', desc: 'Galleries, theatres, cultural centres' },
  { id: 'nightlife', label: '🌙 Nightlife', desc: 'Bars, clubs, night markets' },
  { id: 'wellness', label: '💆 Wellness & Spas', desc: 'Spas, massage, wellness centres' },
  { id: 'sports', label: '⚽ Sports & Activities', desc: 'Adventure, sports venues' },
  { id: 'transport', label: '🚌 Getting Around', desc: 'Key transport tips and hubs' },
];

function MapBounds({ markers }) {
  const map = useMap();
  useEffect(() => {
    if (markers.length > 0) {
      const bounds = L.latLngBounds(markers.map(m => [m.lat, m.lng]));
      map.fitBounds(bounds, { padding: [40, 40] });
    }
  }, [markers, map]);
  return null;
}

function NumberedIcon(number, color = '#00c8ff') {
  return L.divIcon({
    html: `<div style="
      width:28px;height:28px;border-radius:50%;
      background:linear-gradient(135deg,${color},#00a8e8);
      color:#000;font-weight:900;font-size:12px;
      display:flex;align-items:center;justify-content:center;
      border:2px solid #fff;box-shadow:0 2px 8px rgba(0,0,0,0.4);
    ">${number}</div>`,
    className: '',
    iconSize: [28, 28],
    iconAnchor: [14, 14],
  });
}

export default function Itinerary() {
  const navigate = useNavigate();
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [detectedTrip, setDetectedTrip] = useState(null);
  const [showManual, setShowManual] = useState(false);
  const [activeTrip, setActiveTrip] = useState(null);

  // Step 2: Interest selection
  const [showInterests, setShowInterests] = useState(false);
  const [selectedInterests, setSelectedInterests] = useState({});
  const [extraCategories, setExtraCategories] = useState([]);
  const [loadingExtra, setLoadingExtra] = useState(false);

  // Step 3: Suggestions
  const [generating, setGenerating] = useState(false);
  const [suggestions, setSuggestions] = useState(null);
  const [selected, setSelected] = useState({});

  // Step 4: Routing
  const [routing, setRouting] = useState(false);
  const [routedPlan, setRoutedPlan] = useState(null);

  const [error, setError] = useState('');

  // Manual input
  const [destination, setDestination] = useState('');
  const [startDate, setStartDate] = useState('');
  const [duration, setDuration] = useState('');

  useEffect(() => { init(); }, []);

  const init = async () => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) { navigate('/login'); return; }
    setUser(user);
    await detectLatestTrip(user.id);
    setLoading(false);
  };

  const detectLatestTrip = async (userId) => {
    const { data: esimData } = await supabase
      .from('esims')
      .select('country_name, country_flag, activated_at, validity_days, created_at')
      .eq('user_id', userId)
      .order('created_at', { ascending: false })
      .limit(1).single();

    const { data: orderData } = await supabase
      .from('orders')
      .select('*, countries(name, flag_emoji)')
      .eq('user_id', userId)
      .eq('payment_status', 'paid')
      .order('created_at', { ascending: false })
      .limit(1).single();

    let trip = null;
    if (esimData && orderData) {
      trip = new Date(esimData.created_at) >= new Date(orderData.created_at)
        ? buildTripFromEsim(esimData) : buildTripFromOrder(orderData);
    } else if (esimData) { trip = buildTripFromEsim(esimData); }
    else if (orderData) { trip = buildTripFromOrder(orderData); }
    setDetectedTrip(trip);
  };

  const buildTripFromEsim = (e) => ({
    destination: e.country_name, flag: e.country_flag || '🌍',
    startDate: e.activated_at ? new Date(e.activated_at).toISOString().split('T')[0] : new Date().toISOString().split('T')[0],
    duration: e.validity_days || 7, source: 'eSIM',
  });

  const buildTripFromOrder = (o) => ({
    destination: o.countries?.name || 'Your destination', flag: o.countries?.flag_emoji || '🌍',
    startDate: o.paid_at ? new Date(o.paid_at).toISOString().split('T')[0] : new Date().toISOString().split('T')[0],
    duration: 7, source: 'Order',
  });

  const proceedToInterests = async (trip) => {
    setActiveTrip(trip);
    setShowInterests(true);
    setLoadingExtra(true);
    // Ask Claude for destination-specific extra categories
    try {
      const response = await fetch(CLAUDE_API, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model: MODEL, max_tokens: 1000,
          messages: [{
            role: 'user',
            content: `For a trip to ${trip.destination}, suggest 3-5 destination-specific activity categories that are unique or especially relevant to this destination (beyond generic categories like food, shopping, attractions).
Examples for Japan: Onsen & Ryokan, Anime & Pop Culture, Sumo & Martial Arts
Examples for Thailand: Temple Hopping, Muay Thai, Thai Massage
Examples for Italy: Wine Tasting, Cooking Classes, Archaeological Sites

Return ONLY a JSON array, no other text:
[
  { "id": "dest_1", "label": "🎌 Onsen & Ryokan", "desc": "Traditional hot spring baths and inns" },
  { "id": "dest_2", "label": "🍣 Sushi & Ramen Culture", "desc": "Iconic Japanese food experiences" }
]`
          }]
        })
      });
      const data = await response.json();
      const text = data.content?.map(b => b.text || '').join('');
      const clean = text.replace(/```json|```/g, '').trim();
      const parsed = JSON.parse(clean);
      setExtraCategories(parsed);
    } catch (e) {
      setExtraCategories([]);
    }
    setLoadingExtra(false);
  };

  const toggleInterest = (id) => {
    setSelectedInterests(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const selectedInterestLabels = () => {
    const all = [...STANDARD_CATEGORIES, ...extraCategories];
    return all.filter(c => selectedInterests[c.id]).map(c => c.label.replace(/^.{2}/, '').trim());
  };

  const generateSuggestions = async () => {
    const interests = selectedInterestLabels();
    if (interests.length === 0) { setError('Please select at least one interest.'); return; }
    setError('');
    setGenerating(true);
    setSuggestions(null);
    setSelected({});
    setRoutedPlan(null);

    const start = new Date(activeTrip.startDate);
    const end = new Date(start);
    end.setDate(start.getDate() + parseInt(activeTrip.duration) - 1);

    const prompt = `You are an expert travel planner with deep knowledge of verified, accredited establishments worldwide.

Create a ${activeTrip.duration}-day itinerary for ${activeTrip.destination}.
Trip dates: ${start.toDateString()} to ${end.toDateString()}
Selected interests: ${interests.join(', ')}

CRITICAL TRUST & SAFETY RULES — you MUST follow these:
1. ONLY suggest real, verifiable, well-known establishments with confirmed physical addresses
2. Prioritise: UNESCO sites, Michelin-rated restaurants, government tourism board listed attractions, major hotel brands, established retail chains, nationally recognised venues
3. NEVER invent or hallucinate business names, addresses, or locations
4. Every establishment must have a real, specific street address
5. For each item, note the trust source (e.g. "Michelin-listed", "UNESCO World Heritage", "Tourism Board recommended")
6. Distribute activities across the ${activeTrip.duration} days logically

Return ONLY a JSON object, no other text:
{
  "destination": "${activeTrip.destination}",
  "flag": "${activeTrip.flag}",
  "disclaimer": "Suggestions are AI-generated from publicly known, verified establishments. Always confirm opening hours and availability before visiting.",
  "days": [
    {
      "day": 1,
      "date": "Mon, 21 Apr",
      "theme": "Arrival & First Impressions",
      "categories": {
        "Food & Dining": [
          {
            "id": "d1_food_1",
            "name": "Tsukiji Outer Market",
            "address": "4 Chome-16-2 Tsukiji, Chuo City, Tokyo 104-0045, Japan",
            "desc": "World-famous fish market — breakfast sushi and tamagoyaki",
            "duration": "1 hr",
            "trustSource": "Lonely Planet Top Choice",
            "lat": 35.6654,
            "lng": 139.7707
          }
        ]
      }
    }
  ]
}`;

    try {
      const response = await fetch(CLAUDE_API, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ model: MODEL, max_tokens: 1000, messages: [{ role: 'user', content: prompt }] })
      });
      const data = await response.json();
      const text = data.content?.map(b => b.text || '').join('');
      const clean = text.replace(/```json|```/g, '').trim();
      const parsed = JSON.parse(clean);
      setSuggestions(parsed);

      // Pre-select all
      const preSelected = {};
      parsed.days.forEach(day => {
        Object.values(day.categories).forEach(items => {
          items.forEach(item => { preSelected[item.id] = true; });
        });
      });
      setSelected(preSelected);
    } catch (err) {
      setError('Failed to generate suggestions. Please try again.');
    }
    setGenerating(false);
  };

  const toggleItem = (id) => setSelected(prev => ({ ...prev, [id]: !prev[id] }));
  const selectedCount = Object.values(selected).filter(Boolean).length;

  // Collect all items with coords for map
  const getMapMarkers = (data, useSelected = false) => {
    const markers = [];
    if (!data) return markers;
    data.days?.forEach(day => {
      Object.values(day.categories || {}).forEach(items => {
        items?.forEach(item => {
          if (item.lat && item.lng && (!useSelected || selected[item.id])) {
            markers.push({ ...item, day: day.day });
          }
        });
      });
    });
    return markers;
  };

  const getRouteMarkers = (plan) => {
    if (!plan) return [];
    const markers = [];
    plan.days?.forEach(day => {
      day.stops?.forEach(stop => {
        if (stop.lat && stop.lng) markers.push({ ...stop, day: day.day });
      });
    });
    return markers;
  };

  const buildRoute = async () => {
    setRouting(true);
    setError('');

    const selectedByDay = suggestions.days.map(day => {
      const items = [];
      Object.entries(day.categories).forEach(([cat, catItems]) => {
        catItems.forEach(item => {
          if (selected[item.id]) items.push({ ...item, category: cat });
        });
      });
      return { day: day.day, date: day.date, theme: day.theme, items };
    }).filter(d => d.items.length > 0);

    const prompt = `You are a travel routing expert. Optimise a day-by-day route for ${activeTrip.destination}.

Selected activities per day:
${JSON.stringify(selectedByDay, null, 2)}

Rules:
1. Order stops geographically to minimise travel time
2. For each stop provide exact travel time from previous stop
3. Recommend realistic transport mode (Walk / MRT / Metro / Bus / Taxi / Grab / Train / Tuk-tuk etc.)
4. Keep the real address and coordinates from the input data
5. Generate a Google Maps URL per stop

Return ONLY a JSON object, no other text:
{
  "destination": "${activeTrip.destination}",
  "days": [
    {
      "day": 1,
      "date": "Mon, 21 Apr",
      "theme": "Arrival & First Impressions",
      "stops": [
        {
          "order": 1,
          "name": "Tsukiji Outer Market",
          "category": "Food & Dining",
          "address": "4 Chome-16-2 Tsukiji, Chuo City, Tokyo 104-0045, Japan",
          "desc": "Breakfast — fresh sushi and tamagoyaki",
          "duration": "1 hr",
          "trustSource": "Lonely Planet Top Choice",
          "travelFromPrev": null,
          "transportMode": null,
          "lat": 35.6654,
          "lng": 139.7707,
          "mapsUrl": "https://www.google.com/maps/search/?api=1&query=Tsukiji+Outer+Market+Tokyo"
        }
      ]
    }
  ]
}`;

    try {
      const response = await fetch(CLAUDE_API, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ model: MODEL, max_tokens: 1000, messages: [{ role: 'user', content: prompt }] })
      });
      const data = await response.json();
      const text = data.content?.map(b => b.text || '').join('');
      const clean = text.replace(/```json|```/g, '').trim();
      const parsed = JSON.parse(clean);
      setRoutedPlan(parsed);
    } catch (err) {
      setError('Failed to build route. Please try again.');
    }
    setRouting(false);
  };

  const transportIcons = { Walk: '🚶', MRT: '🚇', Metro: '🚇', Bus: '🚌', Taxi: '🚕', Grab: '🚗', Train: '🚆', 'Tuk-tuk': '🛺' };
  const inputStyle = {
    background: 'rgba(255,255,255,0.06)', border: '1px solid var(--border)',
    borderRadius: '10px', padding: '12px 16px', fontSize: '15px',
    color: 'var(--text)', outline: 'none', width: '100%', boxSizing: 'border-box'
  };
  const labelStyle = { fontSize: '13px', fontWeight: 600, color: 'var(--muted)' };

  if (loading) return <div className={styles.loadingPage}><div className={styles.spinner}></div></div>;

  return (
    <div className={styles.page}>
      <Navbar />
      <main className={styles.main}>

        <div className={styles.header}>
          <div>
            <h1 className={styles.title}>My Itinerary ✈️</h1>
            <p style={{ fontSize: '14px', color: 'var(--muted)' }}>AI-powered travel plans — verified places, real addresses, optimised routes</p>
          </div>
        </div>

        {/* ── STEP 1: Trip Selection ── */}
        {!showInterests && !generating && !suggestions && !routedPlan && (
          <>
            {detectedTrip && !showManual && (
              <div style={{
                background: 'rgba(0,200,255,0.06)', border: '1px solid rgba(0,200,255,0.2)',
                borderRadius: '20px', padding: '28px', marginBottom: '20px', maxWidth: '600px'
              }}>
                <div style={{ fontSize: '12px', color: 'var(--accent)', fontWeight: 700, marginBottom: '12px', textTransform: 'uppercase', letterSpacing: '0.5px' }}>
                  📍 Trip detected from your {detectedTrip.source}
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '14px', marginBottom: '20px' }}>
                  <span style={{ fontSize: '40px' }}>{detectedTrip.flag}</span>
                  <div>
                    <div style={{ fontWeight: 900, fontSize: '22px', fontFamily: 'var(--font-head)' }}>{detectedTrip.destination}</div>
                    <div style={{ fontSize: '14px', color: 'var(--muted)' }}>
                      From {new Date(detectedTrip.startDate).toDateString()} · {detectedTrip.duration} days
                    </div>
                  </div>
                </div>
                <p style={{ fontSize: '14px', color: 'var(--muted)', marginBottom: '20px' }}>
                  Want me to plan this trip for you?
                </p>
                <div style={{ display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
                  <button onClick={() => proceedToInterests(detectedTrip)} style={{
                    background: 'linear-gradient(135deg, var(--accent), var(--accent2))',
                    color: '#000', border: 'none', borderRadius: '12px',
                    padding: '12px 24px', fontWeight: 800, fontSize: '14px',
                    fontFamily: 'var(--font-head)', cursor: 'pointer'
                  }}>Yes, plan this trip →</button>
                  <button onClick={() => setShowManual(true)} style={{
                    background: 'rgba(255,255,255,0.06)', color: 'var(--muted)',
                    border: '1px solid var(--border)', borderRadius: '12px',
                    padding: '12px 24px', fontWeight: 600, fontSize: '14px', cursor: 'pointer'
                  }}>Plan a different trip</button>
                </div>
              </div>
            )}

            {(!detectedTrip || showManual) && (
              <div style={{
                background: 'rgba(255,255,255,0.04)', border: '1px solid var(--border)',
                borderRadius: '20px', padding: '28px', maxWidth: '520px', marginBottom: '20px'
              }}>
                <h2 style={{ fontFamily: 'var(--font-head)', fontSize: '18px', fontWeight: 800, marginBottom: '20px' }}>
                  {showManual ? 'Plan a Different Trip' : 'Plan a Trip'}
                </h2>
                <form onSubmit={(e) => { e.preventDefault(); proceedToInterests({ destination, startDate, duration, flag: '🌍' }); }}
                  style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
                    <label style={labelStyle}>Destination</label>
                    <input type="text" placeholder="e.g. Tokyo, Japan" value={destination}
                      onChange={e => setDestination(e.target.value)} required style={inputStyle} />
                  </div>
                  <div style={{ display: 'flex', gap: '12px' }}>
                    <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '6px' }}>
                      <label style={labelStyle}>Start Date</label>
                      <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} required style={inputStyle} />
                    </div>
                    <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '6px' }}>
                      <label style={labelStyle}>Duration (days)</label>
                      <input type="number" placeholder="7" min="1" max="21" value={duration}
                        onChange={e => setDuration(e.target.value)} required style={inputStyle} />
                    </div>
                  </div>
                  <button type="submit" style={{
                    background: 'linear-gradient(135deg, var(--accent), var(--accent2))',
                    color: '#000', border: 'none', borderRadius: '12px', padding: '14px',
                    fontWeight: 800, fontSize: '15px', fontFamily: 'var(--font-head)', cursor: 'pointer'
                  }}>Next: Choose Interests →</button>
                </form>
              </div>
            )}
          </>
        )}

        {/* ── STEP 2: Interest Selection ── */}
        {showInterests && !generating && !suggestions && (
          <div style={{ maxWidth: '680px' }}>
            <div style={{ marginBottom: '24px' }}>
              <h2 style={{ fontFamily: 'var(--font-head)', fontSize: '20px', fontWeight: 900, marginBottom: '6px' }}>
                What are you into? {activeTrip?.flag}
              </h2>
              <p style={{ fontSize: '14px', color: 'var(--muted)' }}>
                Select your interests and we'll suggest verified, accredited places for {activeTrip?.destination}.
              </p>
            </div>

            {/* Standard categories */}
            <div style={{ marginBottom: '24px' }}>
              <div style={{ fontSize: '12px', fontWeight: 700, color: 'var(--muted)', textTransform: 'uppercase', letterSpacing: '0.5px', marginBottom: '12px' }}>
                Standard Categories
              </div>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '10px' }}>
                {STANDARD_CATEGORIES.map(cat => (
                  <label key={cat.id} style={{
                    display: 'flex', alignItems: 'flex-start', gap: '10px', cursor: 'pointer',
                    padding: '12px 14px', borderRadius: '14px',
                    background: selectedInterests[cat.id] ? 'rgba(0,200,255,0.08)' : 'rgba(255,255,255,0.03)',
                    border: `1px solid ${selectedInterests[cat.id] ? 'rgba(0,200,255,0.3)' : 'rgba(255,255,255,0.07)'}`,
                    transition: 'all 0.15s'
                  }}>
                    <input type="checkbox" checked={!!selectedInterests[cat.id]} onChange={() => toggleInterest(cat.id)}
                      style={{ marginTop: '2px', accentColor: 'var(--accent)', width: '15px', height: '15px', flexShrink: 0 }} />
                    <div>
                      <div style={{ fontWeight: 700, fontSize: '13px' }}>{cat.label}</div>
                      <div style={{ fontSize: '11px', color: 'var(--muted)', marginTop: '2px' }}>{cat.desc}</div>
                    </div>
                  </label>
                ))}
              </div>
            </div>

            {/* Destination-specific categories */}
            <div style={{ marginBottom: '28px' }}>
              <div style={{ fontSize: '12px', fontWeight: 700, color: 'var(--accent)', textTransform: 'uppercase', letterSpacing: '0.5px', marginBottom: '12px' }}>
                {loadingExtra ? '⏳ Loading destination-specific categories...' : `✨ Unique to ${activeTrip?.destination}`}
              </div>
              {!loadingExtra && extraCategories.length > 0 && (
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '10px' }}>
                  {extraCategories.map(cat => (
                    <label key={cat.id} style={{
                      display: 'flex', alignItems: 'flex-start', gap: '10px', cursor: 'pointer',
                      padding: '12px 14px', borderRadius: '14px',
                      background: selectedInterests[cat.id] ? 'rgba(0,200,255,0.08)' : 'rgba(255,255,255,0.03)',
                      border: `1px solid ${selectedInterests[cat.id] ? 'rgba(0,200,255,0.3)' : 'rgba(0,200,255,0.12)'}`,
                      transition: 'all 0.15s'
                    }}>
                      <input type="checkbox" checked={!!selectedInterests[cat.id]} onChange={() => toggleInterest(cat.id)}
                        style={{ marginTop: '2px', accentColor: 'var(--accent)', width: '15px', height: '15px', flexShrink: 0 }} />
                      <div>
                        <div style={{ fontWeight: 700, fontSize: '13px' }}>{cat.label}</div>
                        <div style={{ fontSize: '11px', color: 'var(--muted)', marginTop: '2px' }}>{cat.desc}</div>
                      </div>
                    </label>
                  ))}
                </div>
              )}
            </div>

            <div style={{ display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
              <button onClick={() => { setShowInterests(false); setExtraCategories([]); }} style={{
                background: 'rgba(255,255,255,0.06)', border: '1px solid var(--border)',
                color: 'var(--muted)', borderRadius: '12px', padding: '12px 20px',
                fontWeight: 600, fontSize: '14px', cursor: 'pointer'
              }}>← Back</button>
              <button onClick={generateSuggestions} disabled={Object.values(selectedInterests).filter(Boolean).length === 0} style={{
                background: Object.values(selectedInterests).filter(Boolean).length === 0
                  ? 'rgba(255,255,255,0.1)' : 'linear-gradient(135deg, var(--accent), var(--accent2))',
                color: Object.values(selectedInterests).filter(Boolean).length === 0 ? 'var(--muted)' : '#000',
                border: 'none', borderRadius: '12px', padding: '12px 28px',
                fontWeight: 800, fontSize: '15px', fontFamily: 'var(--font-head)',
                cursor: Object.values(selectedInterests).filter(Boolean).length === 0 ? 'not-allowed' : 'pointer'
              }}>
                Generate Suggestions →
              </button>
            </div>
          </div>
        )}

        {/* ── Generating spinner ── */}
        {generating && (
          <div style={{ textAlign: 'center', padding: '60px 24px' }}>
            <div className={styles.spinner} style={{ margin: '0 auto 20px' }}></div>
            <p style={{ color: 'var(--muted)', fontSize: '15px' }}>Finding verified places in {activeTrip?.destination}...</p>
          </div>
        )}

        {/* ── STEP 3: Suggestions + Map ── */}
        {suggestions && !routedPlan && !routing && (
          <div style={{ maxWidth: '760px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '16px', flexWrap: 'wrap', gap: '12px' }}>
              <div>
                <h2 style={{ fontFamily: 'var(--font-head)', fontSize: '20px', fontWeight: 900 }}>
                  {suggestions.flag} {suggestions.destination} — Select Your Activities
                </h2>
                <p style={{ fontSize: '13px', color: 'var(--muted)', marginTop: '4px' }}>
                  Tick what you want · untick what you don't · then build your route
                </p>
              </div>
              <button onClick={() => { setSuggestions(null); setShowInterests(true); }} style={{
                background: 'rgba(255,255,255,0.06)', border: '1px solid var(--border)',
                color: 'var(--muted)', borderRadius: '10px', padding: '8px 16px',
                fontSize: '13px', fontWeight: 600, cursor: 'pointer'
              }}>← Back to Interests</button>
            </div>

            {/* Disclaimer */}
            <div style={{
              background: 'rgba(245,166,35,0.08)', border: '1px solid rgba(245,166,35,0.2)',
              borderRadius: '12px', padding: '10px 14px', fontSize: '12px',
              color: 'rgba(245,166,35,0.9)', marginBottom: '20px'
            }}>
              ℹ️ {suggestions.disclaimer}
            </div>

            {/* Map — Step 3 */}
            {(() => {
              const markers = getMapMarkers(suggestions, true);
              return markers.length > 0 ? (
                <div style={{ borderRadius: '16px', overflow: 'hidden', border: '1px solid var(--border)', marginBottom: '24px', height: '320px' }}>
                  <MapContainer center={[markers[0].lat, markers[0].lng]} zoom={12} style={{ height: '100%', width: '100%' }} scrollWheelZoom={false}>
                    <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" attribution='© OpenStreetMap contributors' />
                    <MapBounds markers={markers} />
                    {markers.map((m, i) => (
                      <Marker key={m.id || i} position={[m.lat, m.lng]} icon={NumberedIcon(i + 1)}>
                        <Popup>
                          <strong>{m.name}</strong><br />
                          <span style={{ fontSize: '11px', color: '#666' }}>{m.address}</span>
                        </Popup>
                      </Marker>
                    ))}
                  </MapContainer>
                </div>
              ) : null;
            })()}

            {/* Select all / deselect all */}
            <div style={{ display: 'flex', gap: '10px', marginBottom: '16px' }}>
              <button onClick={() => {
                const all = {};
                suggestions.days.forEach(d => Object.values(d.categories).forEach(items => items.forEach(i => { all[i.id] = true; })));
                setSelected(all);
              }} style={{ background: 'none', border: '1px solid var(--border)', color: 'var(--muted)', borderRadius: '8px', padding: '6px 14px', fontSize: '12px', fontWeight: 600, cursor: 'pointer' }}>
                Select All
              </button>
              <button onClick={() => setSelected({})} style={{ background: 'none', border: '1px solid var(--border)', color: 'var(--muted)', borderRadius: '8px', padding: '6px 14px', fontSize: '12px', fontWeight: 600, cursor: 'pointer' }}>
                Deselect All
              </button>
            </div>

            {/* Day cards */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
              {suggestions.days.map(day => (
                <div key={day.day} style={{ background: 'rgba(255,255,255,0.04)', border: '1px solid var(--border)', borderRadius: '20px', overflow: 'hidden' }}>
                  <div style={{ background: 'rgba(0,200,255,0.08)', borderBottom: '1px solid var(--border)', padding: '14px 24px', display: 'flex', alignItems: 'baseline', gap: '12px' }}>
                    <span style={{ background: 'var(--accent)', color: '#000', borderRadius: '8px', padding: '2px 10px', fontSize: '12px', fontWeight: 800 }}>Day {day.day}</span>
                    <span style={{ fontSize: '13px', color: 'var(--muted)' }}>{day.date}</span>
                    <span style={{ fontWeight: 700, fontSize: '15px' }}>{day.theme}</span>
                  </div>
                  <div style={{ padding: '20px 24px', display: 'flex', flexDirection: 'column', gap: '18px' }}>
                    {Object.entries(day.categories).map(([cat, items]) => (
                      <div key={cat}>
                        <div style={{ fontSize: '12px', fontWeight: 700, color: 'var(--muted)', textTransform: 'uppercase', letterSpacing: '0.5px', marginBottom: '10px' }}>
                          {cat}
                        </div>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                          {items.map(item => (
                            <label key={item.id} style={{
                              display: 'flex', alignItems: 'flex-start', gap: '12px', cursor: 'pointer',
                              padding: '12px 14px', borderRadius: '12px',
                              background: selected[item.id] ? 'rgba(0,200,255,0.07)' : 'rgba(255,255,255,0.02)',
                              border: `1px solid ${selected[item.id] ? 'rgba(0,200,255,0.25)' : 'rgba(255,255,255,0.06)'}`,
                              transition: 'all 0.15s'
                            }}>
                              <input type="checkbox" checked={!!selected[item.id]} onChange={() => toggleItem(item.id)}
                                style={{ marginTop: '3px', accentColor: 'var(--accent)', width: '16px', height: '16px', flexShrink: 0 }} />
                              <div style={{ flex: 1 }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: '8px', flexWrap: 'wrap' }}>
                                  <div style={{ fontWeight: 700, fontSize: '14px' }}>
                                    {item.name}
                                    {item.duration && <span style={{ fontWeight: 400, color: 'var(--muted)', fontSize: '12px', marginLeft: '8px' }}>· {item.duration}</span>}
                                  </div>
                                  {item.trustSource && (
                                    <span style={{ fontSize: '10px', background: 'rgba(76,217,100,0.1)', color: '#4cd964', border: '1px solid rgba(76,217,100,0.2)', borderRadius: '6px', padding: '2px 7px', whiteSpace: 'nowrap', fontWeight: 700 }}>
                                      ✓ {item.trustSource}
                                    </span>
                                  )}
                                </div>
                                <div style={{ fontSize: '13px', color: 'var(--muted)', marginTop: '3px' }}>{item.desc}</div>
                                {item.address && (
                                  <div style={{ fontSize: '11px', color: 'var(--muted2)', marginTop: '4px', display: 'flex', alignItems: 'center', gap: '4px' }}>
                                    📍 {item.address}
                                  </div>
                                )}
                              </div>
                            </label>
                          ))}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>

            {/* Sticky Build Route CTA */}
            <div style={{
              position: 'sticky', bottom: '24px', marginTop: '24px',
              background: 'rgba(10,15,26,0.95)', border: '1px solid var(--border)',
              borderRadius: '16px', padding: '16px 24px',
              display: 'flex', justifyContent: 'space-between', alignItems: 'center',
              backdropFilter: 'blur(20px)', flexWrap: 'wrap', gap: '12px'
            }}>
              <div style={{ fontSize: '14px', color: 'var(--muted)' }}>
                <span style={{ color: 'var(--text)', fontWeight: 700 }}>{selectedCount}</span> activities selected
              </div>
              <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
                <button onClick={() => { setSuggestions(null); setShowInterests(false); setShowManual(true); }} style={{
                  background: 'none', border: '1px solid var(--border)', color: 'var(--muted)',
                  borderRadius: '10px', padding: '10px 18px', fontSize: '13px', fontWeight: 600, cursor: 'pointer'
                }}>✏️ Plan My Own</button>
                <button onClick={buildRoute} disabled={selectedCount === 0} style={{
                  background: selectedCount === 0 ? 'rgba(255,255,255,0.1)' : 'linear-gradient(135deg, var(--accent), var(--accent2))',
                  color: selectedCount === 0 ? 'var(--muted)' : '#000',
                  border: 'none', borderRadius: '10px', padding: '10px 24px',
                  fontWeight: 800, fontSize: '14px', fontFamily: 'var(--font-head)',
                  cursor: selectedCount === 0 ? 'not-allowed' : 'pointer'
                }}>Build My Route →</button>
              </div>
            </div>
          </div>
        )}

        {/* ── Routing spinner ── */}
        {routing && (
          <div style={{ textAlign: 'center', padding: '60px 24px' }}>
            <div className={styles.spinner} style={{ margin: '0 auto 20px' }}></div>
            <p style={{ color: 'var(--muted)', fontSize: '15px' }}>Optimising your route for {activeTrip?.destination}...</p>
          </div>
        )}

        {/* ── STEP 5: Routed Plan + Map ── */}
        {routedPlan && (
          <div style={{ maxWidth: '760px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px', flexWrap: 'wrap', gap: '12px' }}>
              <div>
                <h2 style={{ fontFamily: 'var(--font-head)', fontSize: '20px', fontWeight: 900 }}>
                  {activeTrip?.flag || '✈️'} {routedPlan.destination} — Your Route
                </h2>
                <p style={{ fontSize: '13px', color: 'var(--muted)', marginTop: '4px' }}>Stops ordered and optimised · tap 📍 Maps for navigation</p>
              </div>
              <div style={{ display: 'flex', gap: '10px' }}>
                <button onClick={() => setRoutedPlan(null)} style={{ background: 'rgba(255,255,255,0.06)', border: '1px solid var(--border)', color: 'var(--muted)', borderRadius: '10px', padding: '8px 16px', fontSize: '13px', fontWeight: 600, cursor: 'pointer' }}>← Edit Selection</button>
                <button onClick={() => { setSuggestions(null); setRoutedPlan(null); setShowInterests(false); setShowManual(false); }} style={{ background: 'rgba(255,255,255,0.06)', border: '1px solid var(--border)', color: 'var(--muted)', borderRadius: '10px', padding: '8px 16px', fontSize: '13px', fontWeight: 600, cursor: 'pointer' }}>Start Over</button>
              </div>
            </div>

            {/* Map — Step 5 */}
            {(() => {
              const markers = getRouteMarkers(routedPlan);
              return markers.length > 0 ? (
                <div style={{ borderRadius: '16px', overflow: 'hidden', border: '1px solid var(--border)', marginBottom: '28px', height: '360px' }}>
                  <MapContainer center={[markers[0].lat, markers[0].lng]} zoom={12} style={{ height: '100%', width: '100%' }} scrollWheelZoom={false}>
                    <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" attribution='© OpenStreetMap contributors' />
                    <MapBounds markers={markers} />
                    {markers.map((m, i) => (
                      <Marker key={i} position={[m.lat, m.lng]} icon={NumberedIcon(m.order || i + 1)}>
                        <Popup>
                          <strong>Stop {m.order}: {m.name}</strong><br />
                          <span style={{ fontSize: '11px', color: '#666' }}>{m.address}</span><br />
                          {m.mapsUrl && <a href={m.mapsUrl} target="_blank" rel="noopener noreferrer" style={{ fontSize: '11px', color: '#0078d4' }}>Open in Maps</a>}
                        </Popup>
                      </Marker>
                    ))}
                  </MapContainer>
                </div>
              ) : null;
            })()}

            {/* Route days */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
              {routedPlan.days?.map(day => (
                <div key={day.day} style={{ background: 'rgba(255,255,255,0.04)', border: '1px solid var(--border)', borderRadius: '20px', overflow: 'hidden' }}>
                  <div style={{ background: 'rgba(0,200,255,0.08)', borderBottom: '1px solid var(--border)', padding: '14px 24px', display: 'flex', alignItems: 'baseline', gap: '12px' }}>
                    <span style={{ background: 'var(--accent)', color: '#000', borderRadius: '8px', padding: '2px 10px', fontSize: '12px', fontWeight: 800 }}>Day {day.day}</span>
                    <span style={{ fontSize: '13px', color: 'var(--muted)' }}>{day.date}</span>
                    <span style={{ fontWeight: 700, fontSize: '15px' }}>{day.theme}</span>
                  </div>
                  <div style={{ padding: '20px 24px' }}>
                    {day.stops?.map((stop, idx) => (
                      <div key={idx}>
                        {stop.travelFromPrev && (
                          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', padding: '6px 0 6px 18px', color: 'var(--muted)', fontSize: '12px' }}>
                            <div style={{ width: '1px', height: '18px', background: 'var(--border)', marginRight: '4px' }}></div>
                            {transportIcons[stop.transportMode] || '🚗'} {stop.transportMode} · {stop.travelFromPrev}
                          </div>
                        )}
                        <div style={{
                          display: 'flex', gap: '14px', alignItems: 'flex-start',
                          padding: '14px', borderRadius: '14px',
                          background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.06)',
                          marginBottom: '4px'
                        }}>
                          <div style={{
                            width: '28px', height: '28px', borderRadius: '50%',
                            background: 'linear-gradient(135deg, var(--accent), var(--accent2))',
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            color: '#000', fontWeight: 900, fontSize: '12px', flexShrink: 0
                          }}>{stop.order}</div>
                          <div style={{ flex: 1 }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: '8px', flexWrap: 'wrap' }}>
                              <div style={{ flex: 1 }}>
                                <div style={{ fontWeight: 700, fontSize: '15px' }}>{stop.name}
                                  {stop.duration && <span style={{ fontWeight: 400, color: 'var(--muted)', fontSize: '12px', marginLeft: '8px' }}>· {stop.duration}</span>}
                                </div>
                                <div style={{ fontSize: '13px', color: 'var(--muted)', marginTop: '2px' }}>{stop.desc}</div>
                                {stop.address && (
                                  <div style={{ fontSize: '11px', color: 'var(--muted2)', marginTop: '4px' }}>📍 {stop.address}</div>
                                )}
                                {stop.trustSource && (
                                  <span style={{ display: 'inline-block', marginTop: '6px', fontSize: '10px', background: 'rgba(76,217,100,0.1)', color: '#4cd964', border: '1px solid rgba(76,217,100,0.2)', borderRadius: '6px', padding: '2px 7px', fontWeight: 700 }}>
                                    ✓ {stop.trustSource}
                                  </span>
                                )}
                              </div>
                              <a href={stop.mapsUrl} target="_blank" rel="noopener noreferrer" style={{
                                background: 'rgba(0,200,255,0.1)', border: '1px solid rgba(0,200,255,0.25)',
                                color: 'var(--accent)', borderRadius: '8px', padding: '6px 12px',
                                fontSize: '12px', fontWeight: 700, textDecoration: 'none', whiteSpace: 'nowrap', flexShrink: 0
                              }}>📍 Maps</a>
                            </div>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>

            {/* Disclaimer footer */}
            <div style={{
              marginTop: '24px', padding: '14px 18px', borderRadius: '12px',
              background: 'rgba(255,255,255,0.03)', border: '1px solid var(--border)',
              fontSize: '12px', color: 'var(--muted)'
            }}>
              ℹ️ {suggestions?.disclaimer || 'Always verify opening hours and availability before visiting.'}
            </div>
          </div>
        )}

        {/* Error */}
        {error && (
          <div style={{
            background: 'rgba(255,80,80,0.1)', border: '1px solid rgba(255,80,80,0.25)',
            color: '#ff6b6b', padding: '12px 16px', borderRadius: '12px',
            fontSize: '14px', marginTop: '20px', maxWidth: '600px'
          }}>{error}</div>
        )}

      </main>
    </div>
  );
}
